import json
# Assuming task_001.output is in JSON format
data = {
  'GDP values in USD/trillions for the top 5 economies in the world in 2026': {
    'United States': {'GDP (USD/trillions)': '31.8', 'Population': '332.6 million'},
    'China': {'GDP (USD/trillions)': '20.6', 'Population': '1.443 billion'},
    'Germany': {'GDP (USD/trillions)': '5.3', 'Population': '83.2 million'},
    'India': {'GDP (USD/trillions)': '4.5', 'Population': '1.380 billion'},
    'Japan': {'GDP (USD/trillions)': '4.3', 'Population': '127.1 million'}
  }
}
result = {}
for country, values in data['GDP values in USD/trillions for the top 5 economies in the world in 2026'].items():
  gdp = float(values['GDP (USD/trillions)'].replace(' trillion', '')) * 1000
  population = float(values['Population'].replace(' million', '').replace(' billion', '*1e9'))
  gdp_per_capita = gdp / population
  result[country] = {'GDP (USD/trillions)': str(gdp/1000), 'Population': str(population), 'GDP per capita': str(gdp_per_capita)}
# Sorting countries by GDP per capita in descending order
sorted_result = dict(sorted(result.items(), key=lambda x: x[1]['GDP per capita'], reverse=True))
print(json.dumps(sorted_result, indent=4))

